195→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
196→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
197→        const pull = starPullOffsets.get(post.id);
198→
199→        const baseX = post.universe_x ?? post.display_x;
200→        const baseY = post.universe_y ?? post.display_y;
201→        if (baseX == null || baseY == null) return null;
202→
203→        return {
204→            x: baseX + galDx + (pull?.dx ?? 0),
205→            y: baseY + galDy + (pull?.dy ?? 0),
206→        };
207→    }, [galaxyPositions, starPullOffsets]);
208→
209→    // ── Hoisted computedStarPositions for sharing across layers ──────
210→    const computedStarPositions = useMemo(() => {
211→        const map = new Map();
212→        for (const post of postArray) {
213→            const uid = post.users?.id ?? post.user_id;
214→            const hashGal = userHomeCoords(uid);
215→            const animGal = galaxyPositions.get(uid);
216→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
217→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
218→            const pull = starPullOffsets.get(post.id);
219→
220→            const baseX = post.universe_x ?? post.display_x;
221→            const baseY = post.universe_y ?? post.display_y;
222→            if (baseX == null || baseY == null) continue;
223→
224→            let x = baseX + galDx + (pull?.dx ?? 0);
225→            let y = baseY + galDy + (pull?.dy ?? 0);
226→
227→            map.set(post.id, { x, y });
228→        }
229→        return map;
230→    }, [postArray, galaxyPositions, starPullOffsets]);
231→
232→    // ── Constellation pull offsets (spring constraint) ─────────────
233→    const acceptedConstellations = useMemo(
234→        () => constellations.filter(c => c.status === 'accepted'),
235→        [constellations]
236→    );
237→
238→    const constellationPullOffsets = useMemo(
239→        () => computeConstellationPullOffsets(acceptedConstellations, computedStarPositions),
240→        [acceptedConstellations, computedStarPositions]
241→    );
242→
243→    // ── Final star positions with constellation pull applied ───────
244→    const finalStarPositions = useMemo(() => {
245→        if (constellationPullOffsets.size === 0) return computedStarPositions;
246→
247→        const map = new Map(computedStarPositions);
248→        for (const [postId, offset] of constellationPullOffsets) {
249→            const pos = map.get(postId);
250→            if (pos) {
251→                map.set(postId, {
252→                    x: pos.x + offset.dx,
253→                    y: pos.y + offset.dy,
254→                });
255→            }
256→        }
257→        return map;
258→    }, [computedStarPositions, constellationPullOffsets]);
