  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Line, Text } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const parseHex = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId }) => {
 12→    const lineRefsMap = useRef(new Map());
 13→    const rafRef = useRef(null);
 14→
 15→    const linkData = useMemo(() => {
 16→        if (!Array.isArray(constellations) || constellations.length === 0) return [];
 17→        return constellations.map((link, i) => {
 18→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 19→            const rgb = parseHex(colorHex);
 20→            const isPending = link.status === 'pending';
 21→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
 22→            return { ...link, rgb, colorHex, isPending, isOwnPending };
 23→        });
 24→    }, [constellations, chainColors, userId]);
 25→
 26→    const animate = useCallback(() => {
 27→        const offset = -performance.now() * 0.06;
 28→        let layer = null;
 29→        lineRefsMap.current.forEach((node) => {
 30→            if (node) {
 31→                node.dashOffset(offset);
 32→                if (!layer) layer = node.getLayer();
 33→            }
 34→        });
 35→        if (layer) layer.batchDraw();
 36→        rafRef.current = requestAnimationFrame(animate);
 37→    }, []);
 38→
 39→    useEffect(() => {
 40→        const hasAccepted = linkData.some((l) => !l.isPending);
 41→        if (!hasAccepted) return;
 42→        rafRef.current = requestAnimationFrame(animate);
 43→        return () => {
 44→            if (rafRef.current) cancelAnimationFrame(rafRef.current);
 45→        };
 46→    }, [animate, linkData]);
 47→
 48→    // Clean up stale refs
 49→    useEffect(() => {
 50→        const activeIds = new Set(linkData.map((l) => l.id));
 51→        lineRefsMap.current.forEach((_, key) => {
 52→            if (!activeIds.has(key)) lineRefsMap.current.delete(key);
 53→        });
 54→    }, [linkData]);
 55→
 56→    if (linkData.length === 0) return null;
 57→
 58→    return (
 59→        <Layer {...layerProps} listening={false}>
 60→            {linkData.map((link) => {
 61→                const posA = computedStarPositions.get(link.star_id_a);
 62→                const posB = computedStarPositions.get(link.star_id_b);
 63→                if (!posA || !posB) return null;
 64→
 65→                const ax = posA.x, ay = posA.y;
 66→                const bx = posB.x, by = posB.y;
 67→                const { rgb } = link;
 68→
 69→                if (link.isPending) {
 70→                    if (!link.isOwnPending) return null;
 71→                    return (
 72→                        <Line
 73→                            key={`pending-${link.id}`}
 74→                            points={[ax, ay, bx, by]}
 75→                            dash={[6, 10]}
 76→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`}
 77→                            strokeWidth={1}
 78→                            lineCap="round"
 79→                            listening={false}
 80→                            perfectDrawEnabled={false}
 81→                        />
 82→                    );
 83→                }
 84→
 85→                const mx = (ax + bx) / 2;
 86→                const my = (ay + by) / 2;
 87→
 88→                return (
 89→                    <React.Fragment key={`constellation-${link.id}`}>
 90→                        {/* Outer glow */}
 91→                        <Line
 92→                            points={[ax, ay, bx, by]}
 93→                            dash={[12, 8]}
 94→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.1)`}
 95→                            strokeWidth={5}
 96→                            opacity={1}
 97→                            lineCap="round"
 98→                            listening={false}
 99→                            perfectDrawEnabled={false}
100→                        />
101→                        {/* Inner energy line — animated dashOffset */}
102→                        <Line
103→                            ref={(node) => {
104→                                if (node) lineRefsMap.current.set(link.id, node);
105→                                else lineRefsMap.current.delete(link.id);
106→                            }}
107→                            points={[ax, ay, bx, by]}
108→                            dash={[12, 8]}
109→                            stroke={`rgba(${rgb.r},${rgb.g},${rgb.b},0.4)`}
110→                            strokeWidth={1.8}
111→                            lineCap="round"
112→                            listening={false}
113→                            perfectDrawEnabled={false}
114→                        />
115→                        {/* Label at midpoint */}
116→                        {link.label && (
117→                            <Text
118→                                x={mx}
119→                                y={my - 14}
120→                                text={link.label}
121→                                fontSize={12}
122→                                fontFamily="sans-serif"
123→                                fill={`rgba(${rgb.r},${rgb.g},${rgb.b},0.7)`}
124→                                align="center"
125→                                offsetX={link.label.length * 3}
126→                                scaleX={1 / zoom}
127→                                scaleY={1 / zoom}
128→                                listening={false}
129→                                perfectDrawEnabled={false}
130→                            />
131→                        )}
132→                    </React.Fragment>
133→                );
134→            })}
135→        </Layer>
136→    );
137→});
138→
139→ConstellationLayer.displayName = 'ConstellationLayer';
140→
141→export default ConstellationLayer;
