 19→import {
 20→    buildSectorIndex,
 21→    computeGalaxyCentroids,
 22→    computeConstellationPullOffsets,
 23→    computeSectorKey,
 24→    getNeighborSectorKeys,
 25→} from './utils/cosmicPhysics';
 26→import { computeConstellationChains, assignChainColors } from './utils/constellationUtils';
 27→import { handleClickProfile } from '../../../helpers/handleClicks';
 28→import styles from './Universe.module.css';
 29→
 30→const SECTOR_SIZE = 2000;
 31→const ENABLE_SETTLED_RPC_SAVE = import.meta.env.VITE_ENABLE_UNIVERSE_SETTLE_SAVE === 'true';
 32→
 33→const Universe = () => {
 34→    const navigate = useNavigate();
 35→    const location = useLocation();
 36→    const { user, session } = useAuth();
 37→    const userId = user?.userData?.[0]?.id || null;
 38→
 39→    const fetchDebounceRef = useRef(null);
 40→    const settleDebounceRef = useRef(null);
 41→    const lastSettledPayloadRef = useRef('');
 42→    const initialFetchResolvedRef = useRef(false);
 43→    const hasAutoFocusedOwnGalaxyRef = useRef(false);
 44→    const ownGalaxyLookupStartedRef = useRef(false);
 45→    const constellationFlyToRef = useRef(location.state?.flyToConstellation || null);
 46→
 47→    const [posts, setPosts] = useState(new Map());
 48→    const [selectedPost, setSelectedPost] = useState(null);
 49→    const [selectedGalaxy, setSelectedGalaxy] = useState(null);
 50→    const [galaxyProfile, setGalaxyProfile] = useState(null);
 51→    const [pulsingId, setPulsingId] = useState(null);
 52→    const [hasOwnPosts, setHasOwnPosts] = useState(userId ? null : false);
 53→    const [isInitialLoading, setIsInitialLoading] = useState(true);
 54→    const [ownGalaxyTarget, setOwnGalaxyTarget] = useState(null);
 55→    const [wormholes, setWormholes] = useState([]);
 56→    const [isWarping, setIsWarping] = useState(false);
 57→    const [constellations, setConstellations] = useState([]);
 58→    const [linkModeError, setLinkModeError] = useState(null);
 59→
 60→    // Gravity data from server (fallback paths when embeddings are unavailable in payload)
 61→    const [centroids, setCentroids] = useState([]);
 62→    const [galaxyEdges, setGalaxyEdges] = useState([]);
 63→    const [similarPairs, setSimilarPairs] = useState([]);
 64→    const [starPulls, setStarPulls] = useState([]);
 65→
 66→    // Shared ref: prevents camera pan while dragging a star
 67→    const isStarDragging = useRef(false);
 68→
 69→    const {
 70→        stageRef, stageSize, camera, zoom, isDragging, centerWorld,
 71→        getLayerProps, getViewportBounds, stageEvents, flyTo, jumpTo, isFlying,
 72→    } = useUniverseCamera(userId, hasOwnPosts, isStarDragging);
 73→
 74→    const {
 75→        isLinkMode, firstStar, isSubmitting, linkModeStatus,
 76→        toggleLinkMode, cancelLinkMode, handleStarClickInLinkMode,
 77→    } = useConstellationLinkMode(userId, session);
 78→
 79→    const postArray = useMemo(() => Array.from(posts.values()), [posts]);
 80→    const showTitles = zoom > 0.5;
 81→
 82→    // Sector partitioning for scalable local gravity math.
 83→    const postSectorIndex = useMemo(() => (
 84→        buildSectorIndex(
 85→            postArray,
 86→            (post) => ({
 87→                x: post?.display_x ?? post?.universe_x,
 88→                y: post?.display_y ?? post?.universe_y,
 89→            }),
 90→            SECTOR_SIZE
 91→        )
 92→    ), [postArray]);
 93→
 94→    const centerSectorKey = useMemo(
 95→        () => computeSectorKey(centerWorld.x, centerWorld.y, SECTOR_SIZE),
 96→        [centerWorld.x, centerWorld.y]
 97→    );
 98→
 99→    const activeSectorKeys = useMemo(
100→        () => new Set(getNeighborSectorKeys(centerSectorKey)),
101→        [centerSectorKey]
102→    );
103→
104→    const activePosts = useMemo(() => {
105→        if (activeSectorKeys.size === 0) return postArray;
106→
107→        const next = [];
108→        for (const key of activeSectorKeys) {
109→            const bucket = postSectorIndex.get(key);
110→            if (bucket?.length) next.push(...bucket);
111→        }
112→        return next;
113→    }, [postArray, postSectorIndex, activeSectorKeys]);
114→
115→    const activePostIds = useMemo(() => {
116→        const ids = new Set();
117→        for (const post of activePosts) {
118→            if (post?.id) ids.add(post.id);
119→        }
120→        return ids;
121→    }, [activePosts]);
122→
123→    const { centroidByUser } = useMemo(
124→        () => computeGalaxyCentroids(postArray),
125→        [postArray]
126→    );
127→
128→    // ── Hash-based galaxies (STARTING positions — always from hash) ──
129→    const hashGalaxies = useMemo(() => {
130→        const seen = new Map();
131→        for (const post of postArray) {
132→            const uid = post.users?.id ?? post.user_id;
133→            if (!uid || seen.has(uid)) continue;
134→            const hash = userHomeCoords(uid);
135→            seen.set(uid, {
136→                userId: uid,
137→                name: post.users?.name ?? post.user_name ?? 'Anonymous',
138→                x: hash.x,
139→                y: hash.y,
140→            });
141→        }
142→        return Array.from(seen.values());
143→    }, [postArray]);
144→
145→    // ── Centroid targets (WHERE galaxies should fly TO) ──────────────
146→    const centroidTargets = useMemo(() => {
147→        const map = new Map();
148→        for (const c of centroids) {
149→            if (c.galaxy_x != null && c.galaxy_y != null) {
150→                map.set(c.user_id, { x: c.galaxy_x, y: c.galaxy_y });
151→            }
152→        }
153→        return map;
154→    }, [centroids]);
155→
156→    // ── Gravity hook: animates galaxies + computes star pull offsets ─
157→    const {
158→        galaxyPositions,
159→        starPullOffsets,
160→        isSettled,
161→        galaxyEdges: effectiveGalaxyEdges,
162→        hasEmbeddingGravity,
163→    } = useCosmicGravity({
164→        galaxies: hashGalaxies,
165→        centroidTargets,
166→        edges: galaxyEdges,
167→        posts: postArray,
168→        starPulls,
169→        centroidByUser,
170→        activeSectorKeys,
171→        activePostIds,
172→        sectorSize: SECTOR_SIZE,
