245→    // ── Final star positions with constellation pull applied ───────
246→    const finalStarPositions = useMemo(() => {
247→        if (constellationPullOffsets.size === 0) return computedStarPositions;
248→
249→        const map = new Map(computedStarPositions);
250→        for (const [postId, offset] of constellationPullOffsets) {
251→            const pos = map.get(postId);
252→            if (pos) {
253→                map.set(postId, {
254→                    x: pos.x + offset.dx,
255→                    y: pos.y + offset.dy,
256→                });
257→            }
258→        }
259→        return map;
260→    }, [computedStarPositions, constellationPullOffsets]);
