 88→export const respondConstellationService = async (userId, constellationId, accept) => {
 89→    if (!userId || !constellationId) {
 90→        throw { status: 400, error: 'userId and constellationId are required' };
 91→    }
 92→
 93→    const { data: constellation, error: errorFetch } = await supabase
 94→        .from('constellations')
 95→        .select('*')
 96→        .eq('id', constellationId)
 97→        .maybeSingle();
 98→
 99→    if (errorFetch) {
100→        console.error('supabase error fetching constellation:', errorFetch.message);
